const finalUrl  = $json.final_url || b.website || '';
const fetchOk   = $json.fetch_ok !== false;
const httpSt    = $json.http_status ?? null;
const warnings  = [];

const PSI_KEY   = 'AIzaSyD5jhTAZnrT_GAQQhaYJSWLe0us4NypLHA';

function norm(v) {
  if (v == null || isNaN(v)) return null;
  const n = Number(v);
  return n <= 1 ? Math.round(n * 100) : Math.round(n);
}

// PSI fetch (async)
async function fetchPSI(url, strategy) {
  if (!url) return null;
  try {
    const q = `url=${encodeURIComponent(url)}&strategy=${strategy}&category=performance&category=seo&category=accessibility&category=best-practices&key=${PSI_KEY}`;
    const resp = await fetch(`https://www.googleapis.com/pagespeedonline/v5/runPagespeed?${q}`);
    return await resp.json();
  } catch(e) { return null; }
}

const [psiMobRaw, psiDesRaw] = await Promise.all([
  fetchPSI(finalUrl, 'mobile'),
  fetchPSI(finalUrl, 'desktop'),
]);

const lhrM = psiMobRaw?.lighthouseResult || {};
const hasPSI = !!(lhrM?.categories?.performance?.score != null);
if (!hasPSI) warnings.push('psi_unavailable');

const psi = {
  performance:    norm(lhrM?.categories?.performance?.score),
  seo:            norm(lhrM?.categories?.seo?.score),
  accessibility:  norm(lhrM?.categories?.accessibility?.score),
  best_practices: norm(lhrM?.categories?.['best-practices']?.score),
  lcp_ms:  lhrM?.audits?.['largest-contentful-paint']?.numericValue ?? null,
  cls:     lhrM?.audits?.['cumulative-layout-shift']?.numericValue ?? null,
};

const screenshotMobile  = lhrM?.audits?.['final-screenshot']?.details?.data ?? null;
const lhrD              = (psiDesRaw?.lighthouseResult) || {};
