function cleanUrl(value) {
  let url = String(value || '').trim();

  url = url.replace(/[\u200B-\u200D\uFEFF]/g, '');
  url = url.replace(/\s+/g, '');

  if (!url) return null;

  if (!/^https?:\/\//i.test(url)) {
    url = 'https://' + url;
  }

  try {
    return new URL(url).href;
  } catch (e) {
    return null;
  }
}

